// Claims the next pending publish job via Supabase RPC.
// Returns job + post data, or hasJob: false if nothing pending.
const SB = $env.SUPABASE_URL;
const SK = $env.SUPABASE_SERVICE_ROLE_KEY;
if (!SB || !SK) return [{ json: { hasJob: false, error: 'Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY' } }];

const h = { apikey: SK, Authorization: 'Bearer ' + SK, 'Content-Type': 'application/json' };
const _http = this.helpers.httpRequest.bind(this.helpers);

try {
  const claimRes = await _http({
    method: 'POST',
    url: SB + '/rest/v1/rpc/claim_publish_job',
    headers: h,
    body: { p_worker_id: 'n8n-' + ($execution?.id || 'manual'), p_claim_seconds: 120 },
  });

  const jobs = Array.isArray(claimRes) ? claimRes : [];
  if (!jobs.length) return [{ json: { hasJob: false } }];
  const job = jobs[0];

  // Fetch full post data
  const postRes = await _http({
    method: 'GET',
    url: SB + '/rest/v1/posts?id=eq.' + job.post_id + '&select=*',
    headers: { apikey: SK, Authorization: 'Bearer ' + SK },
  });

  const posts = Array.isArray(postRes) ? postRes : [];
  if (!posts.length) {
    await _http({ method: 'PATCH', url: SB + '/rest/v1/publish_jobs?id=eq.' + job.id, headers: h, body: { state: 'failed' } });
    return [{ json: { hasJob: false, error: 'Post ' + job.post_id + ' not found' } }];
  }

  const dry_run = $input.first()?.json?.dry_run === true;
  return [{ json: { hasJob: true, dry_run, job, post: posts[0], _results: [] } }];
} catch (err) {
  return [{ json: { hasJob: false, error: 'Claim failed: ' + err.message } }];
}

// Facebook Publisher - Graph API v21
// Credentials: META_PAGE_ACCESS_TOKEN, FACEBOOK_PAGE_ID
const item = $input.item.json;
const r = [...(item._results || [])];
const plat = Array.isArray(item.post?.platforms) ? item.post.platforms : [];

if (!plat.includes('facebook')) return { json: { ...item, _results: [...r, { platform: 'facebook', skipped: true, reason: 'not_targeted' }] } };
if (item.dry_run) return { json: { ...item, _results: [...r, { platform: 'facebook', skipped: true, reason: 'dry_run' }] } };

const TOKEN = $env.META_PAGE_ACCESS_TOKEN;
const PAGE = $env.FACEBOOK_PAGE_ID;
if (!TOKEN || !PAGE) return { json: { ...item, _results: [...r, { platform: 'facebook', success: false, error: 'Missing META_PAGE_ACCESS_TOKEN or FACEBOOK_PAGE_ID' }] } };

let vault = item.post.source_vault || {};
if (typeof vault === 'string') try { vault = JSON.parse(vault); } catch { vault = {}; }
const files = vault.rawFiles || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master?.url) return { json: { ...item, _results: [...r, { platform: 'facebook', success: false, error: 'No media file' }] } };

const _http = this.helpers.httpRequest.bind(this.helpers);
const auth = { Authorization: 'Bearer ' + TOKEN };

try {
  const ct = item.post.content_type || 'image';
  const caption = item.post.caption || '';
  let res;

  if (ct === 'video' || ct === 'reel') {
    res = await _http({ method: 'POST', url: 'https://graph.facebook.com/v21.0/' + PAGE + '/videos', headers: auth, qs: { file_url: master.url, description: caption } });
  } else if (ct === 'carousel' && files.length > 1) {
    const ids = [];
    for (const f of files) {
      if (!f.url) continue;
      const p = await _http({ method: 'POST', url: 'https://graph.facebook.com/v21.0/' + PAGE + '/photos', headers: auth, qs: { url: f.url, published: false } });
      if (p.id) ids.push({ media_fbid: p.id });
    }
    res = await _http({ method: 'POST', url: 'https://graph.facebook.com/v21.0/' + PAGE + '/feed', headers: { ...auth, 'Content-Type': 'application/json' }, body: { message: caption, attached_media: ids } });
  } else {
    res = await _http({ method: 'POST', url: 'https://graph.facebook.com/v21.0/' + PAGE + '/photos', headers: auth, qs: { url: master.url, message: caption } });
  }

  return { json: { ...item, _results: [...r, { platform: 'facebook', success: true, externalPostId: res.id || res.post_id, response: res }] } };
} catch (err) {
  return { json: { ...item, _results: [...r, { platform: 'facebook', success: false, error: err.message }] } };
}

// Instagram Publisher - Container/Poll/Publish pattern
// Credentials: META_PAGE_ACCESS_TOKEN, INSTAGRAM_BUSINESS_ACCOUNT_ID
// Polling: 20 attempts x 3s = 60s max (reduced from 150s)
const item = $input.item.json;
const r = [...(item._results || [])];
const plat = Array.isArray(item.post?.platforms) ? item.post.platforms : [];

if (!plat.includes('instagram')) return { json: { ...item, _results: [...r, { platform: 'instagram', skipped: true, reason: 'not_targeted' }] } };
if (item.dry_run) return { json: { ...item, _results: [...r, { platform: 'instagram', skipped: true, reason: 'dry_run' }] } };

const TOKEN = $env.META_PAGE_ACCESS_TOKEN;
const IG = $env.INSTAGRAM_BUSINESS_ACCOUNT_ID;
if (!TOKEN || !IG) return { json: { ...item, _results: [...r, { platform: 'instagram', success: false, error: 'Missing META_PAGE_ACCESS_TOKEN or INSTAGRAM_BUSINESS_ACCOUNT_ID' }] } };

let vault = item.post.source_vault || {};
if (typeof vault === 'string') try { vault = JSON.parse(vault); } catch { vault = {}; }
const files = vault.rawFiles || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master?.url) return { json: { ...item, _results: [...r, { platform: 'instagram', success: false, error: 'No media file' }] } };

const _http = this.helpers.httpRequest.bind(this.helpers);
const base = 'https://graph.facebook.com/v21.0/' + IG;

async function waitContainer(id) {
  for (let i = 0; i < 20; i++) {
    await new Promise(resolve => setTimeout(resolve, 3000));
    const s = await _http({ method: 'GET', url: 'https://graph.facebook.com/v21.0/' + id, qs: { fields: 'status_code', access_token: TOKEN } });
    if (s.status_code === 'FINISHED') return;
    if (s.status_code === 'ERROR') throw new Error('Container error: ' + JSON.stringify(s));
  }
  throw new Error('Container timed out after 60s');
}

try {
  const ct = item.post.content_type || 'image';
  const caption = item.post.caption || '';
  let publishId;

  if (ct === 'carousel' && files.length > 1) {
    const childIds = [];
    for (const f of files) {
      if (!f.url) continue;
      const isVideo = (f.mimeType || '').startsWith('video/');
      const qs = isVideo
        ? { media_type: 'VIDEO', video_url: f.url, is_carousel_item: true, access_token: TOKEN }
        : { image_url: f.url, is_carousel_item: true, access_token: TOKEN };
      const c = await _http({ method: 'POST', url: base + '/media', qs });
      if (isVideo) await waitContainer(c.id);
      childIds.push(c.id);
    }
    const container = await _http({ method: 'POST', url: base + '/media', qs: { media_type: 'CAROUSEL', children: childIds.join(','), caption, access_token: TOKEN } });
    await waitContainer(container.id);
    const pub = await _http({ method: 'POST', url: base + '/media_publish', qs: { creation_id: container.id, access_token: TOKEN } });
    publishId = pub.id;
  } else if (ct === 'video' || ct === 'reel') {
    const container = await _http({ method: 'POST', url: base + '/media', qs: { media_type: 'REELS', video_url: master.url, caption, access_token: TOKEN } });
    await waitContainer(container.id);
    const pub = await _http({ method: 'POST', url: base + '/media_publish', qs: { creation_id: container.id, access_token: TOKEN } });
    publishId = pub.id;
  } else {
    const container = await _http({ method: 'POST', url: base + '/media', qs: { image_url: master.url, caption, access_token: TOKEN } });
    await waitContainer(container.id);
    const pub = await _http({ method: 'POST', url: base + '/media_publish', qs: { creation_id: container.id, access_token: TOKEN } });
    publishId = pub.id;
  }

  return { json: { ...item, _results: [...r, { platform: 'instagram', success: true, externalPostId: publishId }] } };
} catch (err) {
  return { json: { ...item, _results: [...r, { platform: 'instagram', success: false, error: err.message }] } };
}

// LinkedIn Publisher - NEW /rest/posts API (replaces deprecated /v2/ugcPosts)
// Credentials: LINKEDIN_ACCESS_TOKEN, LINKEDIN_ORG_URN
// Required headers: LinkedIn-Version, X-Restli-Protocol-Version
const item = $input.item.json;
const r = [...(item._results || [])];
const plat = Array.isArray(item.post?.platforms) ? item.post.platforms : [];

if (!plat.includes('linkedin')) return { json: { ...item, _results: [...r, { platform: 'linkedin', skipped: true, reason: 'not_targeted' }] } };
if (item.dry_run) return { json: { ...item, _results: [...r, { platform: 'linkedin', skipped: true, reason: 'dry_run' }] } };

const TOKEN = $env.LINKEDIN_ACCESS_TOKEN;
const ORG = $env.LINKEDIN_ORG_URN;
if (!TOKEN || !ORG) return { json: { ...item, _results: [...r, { platform: 'linkedin', success: false, error: 'Missing LINKEDIN_ACCESS_TOKEN or LINKEDIN_ORG_URN' }] } };

let vault = item.post.source_vault || {};
if (typeof vault === 'string') try { vault = JSON.parse(vault); } catch { vault = {}; }
const files = vault.rawFiles || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master?.url) return { json: { ...item, _results: [...r, { platform: 'linkedin', success: false, error: 'No media file' }] } };

const _http = this.helpers.httpRequest.bind(this.helpers);
const liH = { Authorization: 'Bearer ' + TOKEN, 'Content-Type': 'application/json', 'LinkedIn-Version': '202411', 'X-Restli-Protocol-Version': '2.0.0' };

try {
  const ct = item.post.content_type || 'image';
  const caption = item.post.caption || '';
  const postBody = { author: ORG, commentary: caption, visibility: 'PUBLIC', distribution: { feedDistribution: 'MAIN_FEED', targetEntities: [], thirdPartyDistributionChannels: [] }, lifecycleState: 'PUBLISHED' };

  if (ct === 'video' || ct === 'reel') {
    // Video upload via /rest/videos
    const binary = await _http({ method: 'GET', url: master.url, encoding: 'arraybuffer' });
    const fileSize = binary.byteLength || binary.length || 10000000;
    const init = await _http({ method: 'POST', url: 'https://api.linkedin.com/rest/videos?action=initializeUpload', headers: liH, body: { initializeUploadRequest: { owner: ORG, fileSizeBytes: fileSize, uploadCaptions: false, uploadThumbnail: false } } });
    const uploadUrl = init.value?.uploadInstructions?.[0]?.uploadUrl;
    const videoUrn = init.value?.video;
    if (!uploadUrl || !videoUrn) throw new Error('Video upload init failed: ' + JSON.stringify(init));
    await _http({ method: 'PUT', url: uploadUrl, headers: { Authorization: 'Bearer ' + TOKEN, 'Content-Type': 'application/octet-stream' }, body: binary });
    postBody.content = { media: { id: videoUrn } };
  } else {
    // Image upload via /rest/images
    const binary = await _http({ method: 'GET', url: master.url, encoding: 'arraybuffer' });
    const init = await _http({ method: 'POST', url: 'https://api.linkedin.com/rest/images?action=initializeUpload', headers: liH, body: { initializeUploadRequest: { owner: ORG } } });
    const uploadUrl = init.value?.uploadUrl;
    const imageUrn = init.value?.image;
    if (!uploadUrl || !imageUrn) throw new Error('Image upload init failed: ' + JSON.stringify(init));
    await _http({ method: 'PUT', url: uploadUrl, headers: { Authorization: 'Bearer ' + TOKEN }, body: binary });
    postBody.content = { media: { id: imageUrn } };
  }

  const res = await _http({ method: 'POST', url: 'https://api.linkedin.com/rest/posts', headers: liH, body: postBody, returnFullResponse: true });
  const postId = res.headers?.['x-restli-id'] || res.body?.id || 'unknown';
  return { json: { ...item, _results: [...r, { platform: 'linkedin', success: true, externalPostId: postId, response: res.body || res }] } };
} catch (err) {
  return { json: { ...item, _results: [...r, { platform: 'linkedin', success: false, error: err.message }] } };
}

// YouTube Publisher - Data API v3 resumable upload
// Credentials: YOUTUBE_ACCESS_TOKEN (Google OAuth2)
// Supports: video, reel (as Shorts with #Shorts tag), story
// Skips: image, carousel
const item = $input.item.json;
const r = [...(item._results || [])];
const plat = Array.isArray(item.post?.platforms) ? item.post.platforms : [];

if (!plat.includes('youtube')) return { json: { ...item, _results: [...r, { platform: 'youtube', skipped: true, reason: 'not_targeted' }] } };
if (item.dry_run) return { json: { ...item, _results: [...r, { platform: 'youtube', skipped: true, reason: 'dry_run' }] } };

const TOKEN = $env.YOUTUBE_ACCESS_TOKEN;
if (!TOKEN) return { json: { ...item, _results: [...r, { platform: 'youtube', success: false, error: 'Missing YOUTUBE_ACCESS_TOKEN' }] } };

const ct = item.post.content_type || 'image';
if (ct === 'image' || ct === 'carousel') return { json: { ...item, _results: [...r, { platform: 'youtube', skipped: true, reason: 'image_not_supported' }] } };

let vault = item.post.source_vault || {};
if (typeof vault === 'string') try { vault = JSON.parse(vault); } catch { vault = {}; }
const files = vault.rawFiles || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master?.url) return { json: { ...item, _results: [...r, { platform: 'youtube', success: false, error: 'No media file' }] } };

const _http = this.helpers.httpRequest.bind(this.helpers);
const title = item.post.title || 'Untitled';
const description = item.post.caption || '';
const isShort = ct === 'reel' || ct === 'story';

try {
  const binary = await _http({ method: 'GET', url: master.url, encoding: 'arraybuffer' });
  const size = binary.byteLength || binary.length;

  // Initialize resumable upload
  const initRes = await _http({
    method: 'POST',
    url: 'https://www.googleapis.com/upload/youtube/v3/videos?uploadType=resumable&part=snippet,status',
    headers: { Authorization: 'Bearer ' + TOKEN, 'Content-Type': 'application/json', 'X-Upload-Content-Type': 'video/*', 'X-Upload-Content-Length': String(size) },
    body: { snippet: { title: isShort ? title + ' #Shorts' : title, description, categoryId: '22' }, status: { privacyStatus: 'public', selfDeclaredMadeForKids: false } },
    returnFullResponse: true,
  });

  const uploadUrl = initRes.headers?.location;
  if (!uploadUrl) throw new Error('No upload URL from YouTube init');

  const uploadRes = await _http({ method: 'PUT', url: uploadUrl, headers: { 'Content-Type': 'video/*' }, body: binary });
  return { json: { ...item, _results: [...r, { platform: 'youtube', success: true, externalPostId: uploadRes.id, response: uploadRes }] } };
} catch (err) {
  return { json: { ...item, _results: [...r, { platform: 'youtube', success: false, error: err.message }] } };
}

// TikTok Publisher - Content Posting API v2
// Credentials: TIKTOK_ACCESS_TOKEN, TIKTOK_OPEN_ID
// Supports: video, reel only. Skips image/carousel.
const item = $input.item.json;
const r = [...(item._results || [])];
const plat = Array.isArray(item.post?.platforms) ? item.post.platforms : [];

if (!plat.includes('tiktok')) return { json: { ...item, _results: [...r, { platform: 'tiktok', skipped: true, reason: 'not_targeted' }] } };
if (item.dry_run) return { json: { ...item, _results: [...r, { platform: 'tiktok', skipped: true, reason: 'dry_run' }] } };

const TOKEN = $env.TIKTOK_ACCESS_TOKEN;
if (!TOKEN) return { json: { ...item, _results: [...r, { platform: 'tiktok', success: false, error: 'Missing TIKTOK_ACCESS_TOKEN' }] } };

const ct = item.post.content_type || 'image';
if (ct === 'image' || ct === 'carousel') return { json: { ...item, _results: [...r, { platform: 'tiktok', skipped: true, reason: 'image_not_supported' }] } };

let vault = item.post.source_vault || {};
if (typeof vault === 'string') try { vault = JSON.parse(vault); } catch { vault = {}; }
const files = vault.rawFiles || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master?.url) return { json: { ...item, _results: [...r, { platform: 'tiktok', success: false, error: 'No media file' }] } };

const _http = this.helpers.httpRequest.bind(this.helpers);
const caption = (item.post.caption || '').substring(0, 2200);

try {
  const binary = await _http({ method: 'GET', url: master.url, encoding: 'arraybuffer' });
  const fileSize = binary.byteLength || binary.length;

  const initRes = await _http({
    method: 'POST',
    url: 'https://open.tiktokapis.com/v2/post/publish/video/init/',
    headers: { Authorization: 'Bearer ' + TOKEN, 'Content-Type': 'application/json' },
    body: {
      post_info: { title: caption, privacy_level: 'PUBLIC_TO_EVERYONE', disable_duet: false, disable_comment: false, disable_stitch: false },
      source_info: { source: 'FILE_UPLOAD', video_size: fileSize, chunk_size: fileSize, total_chunk_count: 1 },
    },
  });

  const uploadUrl = initRes.data?.upload_url;
  const publishId = initRes.data?.publish_id;
  if (!uploadUrl) throw new Error('TikTok init failed: ' + JSON.stringify(initRes));

  await _http({
    method: 'PUT',
    url: uploadUrl,
    headers: { 'Content-Type': 'video/mp4', 'Content-Range': 'bytes 0-' + (fileSize - 1) + '/' + fileSize },
    body: binary,
  });

  return { json: { ...item, _results: [...r, { platform: 'tiktok', success: true, externalPostId: publishId, response: initRes }] } };
} catch (err) {
  return { json: { ...item, _results: [...r, { platform: 'tiktok', success: false, error: err.message }] } };
}

// Finalize Job: write per-platform results to platform_publish_attempts,
// update publish_jobs state, update posts.stage if any platform succeeded.
const item = $input.first().json;
const results = item._results || [];
const SB = $env.SUPABASE_URL;
const SK = $env.SUPABASE_SERVICE_ROLE_KEY;
const h = { apikey: SK, Authorization: 'Bearer ' + SK, 'Content-Type': 'application/json', Prefer: 'return=minimal' };
const _http = this.helpers.httpRequest.bind(this.helpers);

const succeeded = results.filter(x => x.success);
const failed = results.filter(x => !x.success && !x.skipped);

// Write per-platform attempt results
for (const result of results) {
  if (result.skipped) continue;
  try {
    await _http({
      method: 'PATCH',
      url: SB + '/rest/v1/platform_publish_attempts?job_id=eq.' + item.job.id + '&platform=eq.' + result.platform,
      headers: h,
      body: {
        state: result.success ? 'succeeded' : 'failed',
        external_post_id: result.externalPostId || null,
        response_payload: result.response ? JSON.stringify(result.response) : null,
        error_message: result.error || null,
        attempt_count: 1,
        updated_at: new Date().toISOString(),
      },
    });
  } catch (err) {
    console.error('Failed to update attempt for ' + result.platform + ': ' + err.message);
  }
}

// Determine overall job state
let jobState;
if (succeeded.length > 0 && failed.length === 0) jobState = 'succeeded';
else if (succeeded.length > 0 && failed.length > 0) jobState = 'partial';
else if (failed.length > 0) jobState = 'failed';
else jobState = 'succeeded';

// Update publish_jobs
await _http({
  method: 'PATCH',
  url: SB + '/rest/v1/publish_jobs?id=eq.' + item.job.id,
  headers: h,
  body: { state: jobState, worker_id: null, claim_expires_at: null, updated_at: new Date().toISOString() },
});

// Update post stage to posted if any platform succeeded
if (jobState === 'succeeded' || jobState === 'partial') {
  await _http({
    method: 'PATCH',
    url: SB + '/rest/v1/posts?id=eq.' + item.post.id,
    headers: h,
    body: { stage: 'posted', updated_at: new Date().toISOString() },
  });
}

// If all failed, check if we should dead-letter
if (jobState === 'failed') {
  try {
    await _http({
      method: 'POST',
      url: SB + '/rest/v1/rpc/dead_letter_publish_job',
      headers: { apikey: SK, Authorization: 'Bearer ' + SK, 'Content-Type': 'application/json' },
      body: { p_job_id: item.job.id, p_reason: 'All platforms failed: ' + failed.map(f => f.platform + ': ' + f.error).join('; ') },
    });
  } catch (err) {
    console.error('Dead letter failed: ' + err.message);
  }
}

return [{
  json: {
    ...item,
    jobState,
    publishedCount: succeeded.length,
    failedCount: failed.length,
    hasFailures: failed.length > 0,
    audit: {
      executionId: $execution?.id || 'manual',
      timestamp: new Date().toISOString(),
      postId: item.post.id,
      postTitle: item.post.title,
      jobId: item.job.id,
      jobState,
      platforms: results.map(x => ({ platform: x.platform, state: x.success ? 'succeeded' : x.skipped ? 'skipped' : 'failed', externalPostId: x.externalPostId || null, error: x.error || null })),
    },
  },
}];

// Log structured audit entry to post_audit_logs
const item = $input.first().json;
const SB = $env.SUPABASE_URL;
const SK = $env.SUPABASE_SERVICE_ROLE_KEY;
const h = { apikey: SK, Authorization: 'Bearer ' + SK, 'Content-Type': 'application/json', Prefer: 'return=minimal' };

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SB + '/rest/v1/post_audit_logs',
    headers: h,
    body: {
      post_id: item.post.id,
      user_name: 'n8n Auto-Publisher',
      action_type: 'auto_published',
      details: JSON.stringify(item.audit),
    },
  });
} catch (err) {
  console.error('Audit log write failed: ' + err.message);
}

return [{ json: item }];

// Send failure alert via webhook (Slack/Teams/email)
const item = $input.first().json;
const failed = (item._results || []).filter(x => !x.success && !x.skipped);

const message = 'Auto-Publisher Alert\n' +
  'Post: ' + (item.post?.title || 'Unknown') + '\n' +
  'Job: ' + (item.job?.id || 'Unknown') + '\n' +
  'State: ' + item.jobState + '\n' +
  'Failed platforms:\n' +
  failed.map(f => '  - ' + f.platform + ': ' + f.error).join('\n');

console.log('[PUBLISH ALERT]', message);

const webhook = $env.ALERT_WEBHOOK_URL;
if (webhook) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: webhook,
      headers: { 'Content-Type': 'application/json' },
      body: { text: message },
    });
  } catch (err) {
    console.error('[ALERT] Webhook failed: ' + err.message);
  }
}

return [{ json: item }];
